// vcnBillLineLabel formats a Bill line as "{product} · qty@unit" for
// the OriginalBillLineID dropdown. Pure function; safe in templ.
func vcnBillLineLabel(bl models.BillLine) string {
	name := bl.Description
	if bl.ProductService != nil && bl.ProductService.Name != "" {
		name = bl.ProductService.Name
	}
	return fmt.Sprintf("%s · %s @ %s", name, bl.Qty.String(), bl.UnitPrice.StringFixed(2))
}

// vcnInitialLinesJSON produces the JSON literal that seeds the
// Alpine.js lines array. Called once at templ render; the operator's
// subsequent edits run entirely client-side.
func vcnInitialLinesJSON(vm VendorCreditNoteDetailVM) string {
	if len(vm.CreditNote.Lines) == 0 {
		return `[{description:'',product_service_id:'',original_bill_line_id:'',qty:'1',unit_price:'0'}]`
	}
	out := "["
	for i, l := range vm.CreditNote.Lines {
		if i > 0 {
			out += ","
		}
		ps := ""
		if l.ProductServiceID != nil {
			ps = fmt.Sprintf("%d", *l.ProductServiceID)
		}
		ob := ""
		if l.OriginalBillLineID != nil {
			ob = fmt.Sprintf("%d", *l.OriginalBillLineID)
		}
		out += fmt.Sprintf(
			"{description:'%s',product_service_id:'%s',original_bill_line_id:'%s',qty:'%s',unit_price:'%s'}",
			vcnEscapeJS(l.Description),
			ps, ob,
			l.Qty.String(), l.UnitPrice.StringFixed(2),
		)
	}
	out += "]"
	return out
}

// vcnLineEditorData returns the Alpine x-data initialiser. Kept in a
// helper so the string literal doesn't poison the templ parser.
func vcnLineEditorData(initial string) string {
	return "{ lines: " + initial + ", addLine() { this.lines.push({description:'',product_service_id:'',original_bill_line_id:'',qty:'1',unit_price:'0'}); }, removeLine(idx) { if (this.lines.length > 1) this.lines.splice(idx, 1); } }"
}

// vcnEscapeJS minimally escapes strings that flow into a JS single-
// quoted literal. Scope: description text only; other fields are
// numeric / id strings.
func vcnEscapeJS(s string) string {
	// Replace backslash first so subsequent escapes don't double up.
	out := ""
	for _, r := range s {
		switch r {
		case '\\':
			out += `\\`
		case '\'':
			out += `\'`
		case '\n', '\r':
			out += " "
		case '<':
			out += `\u003c`
		case '>':
			out += `\u003e`
		default:
			out += string(r)
		}
	}
	return out
}

func vcnRemainingClass(vcn models.VendorCreditNote) string {
	if vcn.RemainingAmount.IsZero() {
		return "text-text-muted"
	}
	return "text-success-hover"
}

